Javascript.transformToModel:
		  
if (null == value || "" == value) {
	return "0.00"; }
else {
	return value; }

Javascript.miscCode:
			function validatePrePaid( maxVal, notAmountErrMsg)
			{
				 var value = Services.getValue(PrePaid.dataBinding);	      			      
			      var err = validateCurrencyValue(value, maxVal); 			      
			      if( err == null)
			      { 	        
				      //must be less than Q39 + Q38
				      var costStg = Services.getValue(CostAmount.dataBinding);
				      var cost = 0;
				      if( null != costStg && costStg.length > 0)
				      { cost = parseFloat(costStg,10);
				      }
				      var jAmntStg = Services.getValue(JudgmentAmount.dataBinding);
				      var jAmnt = 0;
				      if( null != jAmntStg && jAmntStg.length > 0)
				      {  jAmnt = parseFloat(jAmntStg, 10);
				      }
				      var prepaidamt = parseFloat( value );
				      		        		      
				      if( prepaidamt >= (cost + jAmnt))
				      {  err = ErrorCode.getErrorCode("CaseMan_payedbefore_exceeds_total_amount");		        		       
				      }
				      else
				      {	var returnVal = WPU.formatToTwoDP(value);		      	
						Services.setValue(PrePaid.dataBinding, returnVal);
				      }		      		      			 			      			 
				   }				   
				   return err;		   	       
			}

			function DefaultCurrency40() {}
			DefaultCurrency40.dataBinding = "/ds/EnterVariableData/curr1";
			DefaultCurrency40.tabIndex = -1;
			DefaultCurrency40.maxLength = 3;
			DefaultCurrency40.isReadOnly = function(){return true;}
			DefaultCurrency40.isTemporary = function(){return true;}
			DefaultCurrency40.transformToDisplay = function(value){
				return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
			DefaultCurrency40.transformToModel = function(value){
				return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
